script:
frappe.ui.form.on('Blogs', {
    title: function(frm) {
        if (frm.doc.blog_name) {
            let slug = frm.doc.blog_name
                .toLowerCase()
                .trim()
                .replace(/\s+/g, '-')
                .replace(/[^\w-]/g, '');

            frm.set_value('url', slug);
        }
    }
});
